export type RiskSource = "internal" | "regional" | "riskIntelligence" | "strategicInsights"
export type Stage = "exploration" | "fel1" | "fel2" | "fel3" | "execution" | "operations"
export type Region = "ksa" | "europe" | "africa" | "americas" | "global"

export const STAGES: { key: Stage; label: string; gate: string; color: string }[] = [
  { key: "exploration", label: "Exploration", gate: "Gate 1", color: "#7B93DB" },
  { key: "fel1", label: "Scoping (FEL 1)", gate: "Gate 2", color: "#5CB4A5" },
  { key: "fel2", label: "Pre-Feasibility (FEL 2)", gate: "Gate 3", color: "#B4A56F" },
  { key: "fel3", label: "Feasibility (FEL 3)", gate: "Gate 4", color: "#E8A54F" },
  { key: "execution", label: "Execution", gate: "Gate 5", color: "#E05252" },
  { key: "operations", label: "Operations / Closure", gate: "Post-Gate", color: "#8A8577" },
]

export const REGIONS: { key: Region; label: string; flag: string; color: string }[] = [
  { key: "ksa", label: "Saudi Arabia", flag: "\u{1F1F8}\u{1F1E6}", color: "#5CB4A5" },
  { key: "europe", label: "Europe", flag: "\u{1F1EA}\u{1F1FA}", color: "#7B93DB" },
  { key: "africa", label: "Africa", flag: "\u{1F30D}", color: "#E8A54F" },
  { key: "americas", label: "Americas", flag: "\u{1F30E}", color: "#E05252" },
  { key: "global", label: "Global", flag: "\u{1F310}", color: "#B4A56F" },
]

export function getRegionInfo(region: Region) {
  return REGIONS.find((r) => r.key === region) || REGIONS[4]
}

export const SAR_TO_USD = 0.2666

export interface Risk {
  id: string
  name: string
  category: string
  likelihood: number
  impact: number
  owner: string
  status: "active" | "mitigated" | "monitoring" | "opportunity"
  lastUpdated: string
  causes: string[]
  impacts: string[]
  controls: string[]
  source: RiskSource
  sourceDetail?: string
  stage: Stage
  gateRequirement?: string
  financialExposure?: string
  region: Region
  crossBorderImpact?: string
  mitigationTimeline?: { phase: string; date: string; status: "done" | "active" | "pending" }[]
}

function r(
  id: string, name: string, cat: string, l: number, i: number,
  owner: string, status: Risk["status"], date: string,
  source: RiskSource, sd: string, stage: Stage, gate: string, fin: string,
  causes: string[], impacts: string[], controls: string[],
  region: Region = "ksa", crossBorder?: string,
  tl?: Risk["mitigationTimeline"]
): Risk {
  return { id, name, category: cat, likelihood: l, impact: i, owner, status, lastUpdated: date, source, sourceDetail: sd, stage, gateRequirement: gate, financialExposure: fin, causes, impacts, controls, region, crossBorderImpact: crossBorder, mitigationTimeline: tl }
}

