export const likelihoodLabels = ["Rare", "Unlikely", "Possible", "Likely", "Almost Certain"]
export const impactLabels = ["Insignificant", "Minor", "Moderate", "Major", "Catastrophic"]

export function getRiskColor(l: number, i: number): string {
  const s = l * i
  if (s >= 20) return "var(--risk-critical)"
  if (s >= 12) return "var(--risk-high)"
  if (s >= 6) return "var(--risk-medium)"
  if (s >= 3) return "var(--risk-low)"
  return "var(--risk-minimal)"
}

export function getRiskLevel(l: number, i: number): string {
  const s = l * i
  if (s >= 20) return "Critical"
  if (s >= 12) return "High"
  if (s >= 6) return "Medium"
  if (s >= 3) return "Low"
  return "Minimal"
}

export function getSourceLabel(src: RiskSource): string {
  switch (src) {
    case "riskIntelligence": return "Risk Intelligence 2026"
    case "strategicInsights": return "Strategic Insights"
    case "regional": return "KSA Regional"
    default: return "Internal"
  }
}

export function getSourceColor(src: RiskSource): string {
  switch (src) {
    case "riskIntelligence": return "#7B93DB"
    case "strategicInsights": return "#5CB4A5"
    case "regional": return "#E8A54F"
    default: return "#8A8577"
  }
}

